from flask import Flask, request, jsonify
import os
import pickle
import tempfile
import werkzeug
from werkzeug.utils import secure_filename
from itsdangerous import URLSafeSerializer
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)

# Serializer for secure filename handling
serializer = URLSafeSerializer('secret-key')

# Directory to store uploaded models
UPLOAD_FOLDER = tempfile.mkdtemp()
ALLOWED_EXTENSIONS = {'pkl'}

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def validate_and_load_model(file_path):
    try:
        with open(file_path, 'rb') as model_file:
            model = pickle.load(model_file)
            # Add additional validation checks for the model here
            return model
    except Exception as e:
        logging.error(f"Error loading model: {e}")
        return None

@app.route('/upload', methods=['POST'])
def upload_model():
    if 'model' not in request.files:
        return jsonify({'error': 'No file part'}), 400

    file = request.files['model']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)

        model = validate_and_load_model(file_path)
        if model is None:
            return jsonify({'error': 'Invalid model file'}), 400

        # Serialize filename for secure reference
        serialized_filename = serializer.dumps(filename)
        return jsonify({'message': 'Model uploaded successfully', 'model_id': serialized_filename}), 200

    return jsonify({'error': 'File type not allowed'}), 400

@app.route('/predict/<model_id>', methods=['POST'])
def predict(model_id):
    try:
        filename = serializer.loads(model_id)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        
        model = validate_and_load_model(file_path)
        if model is None:
            return jsonify({'error': 'Invalid model file'}), 400

        data = request.json.get('data')
        if not data:
            return jsonify({'error': 'No data provided for prediction'}), 400

        # Perform prediction
        prediction = model.predict([data])
        return jsonify({'prediction': prediction.tolist()}), 200

    except (werkzeug.exceptions.BadRequest, Exception) as e:
        logging.error(f"Error during prediction: {e}")
        return jsonify({'error': 'Invalid request or model'}), 400

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)